  const diClipped = bhData.filter(d => d.di <= yMax * 1.05);

  g.append("path")
    .datum(diClipped)
    .attr("fill", "none")
    .attr("stroke", "red")
    .attr("stroke-width", 2)
    .attr("stroke-dasharray", "6,4")
    .attr("d", diLine);

  // DI label
  const diLabelIdx = Math.min(Math.floor(nPts * 0.15), diClipped.length - 1);
  if (diClipped.length > 2) {
    const lbl = diClipped[diLabelIdx];
    g.append("text")
      .attr("x", x(lbl.nt) + 5)
      .attr("y", y(lbl.di) - 8)
      .attr("fill", "red")
      .attr("font-size", "11px")
      .text(`DI: N(t+1) = α × Nt`);
  }

  // BH curve (black solid)
  const bhLine = d3.line()
    .x(d => x(d.nt))
